import React, { useState, useEffect, useMemo, useRef } from 'react';
import Card from './common/Card';
import Input from './common/Input';
import TextArea from './common/TextArea';
import Button from './common/Button';
import Spinner from './common/Spinner';
import FileUpload from './common/FileUpload';
import { generateInvoiceHtml } from '../services/geminiService';
import type { InvoiceDetails, InvoiceItem, InvoiceTheme } from '../types';
import { useClients } from '../hooks/useClients';
import type { ToastType } from './common/Toast';

declare global {
    interface Window {
        jspdf: any;
        html2canvas: any;
    }
}

const STORAGE_KEYS = {
    LAST_NUMBER: 'sme-pal-last-invoice-number',
    TEMPLATES: 'sme-pal-invoice-templates',
    BRANDING: 'sme-pal-invoice-branding-profiles'
};

const DEFAULT_INVOICE_NUMBER = 'INV-1001';

const getNextInvoiceNumber = (currentNumber: string): string => {
    const numberMatch = currentNumber.match(/\d+$/);
    if (!numberMatch) return `${currentNumber}-1`;
    const numStr = numberMatch[0];
    const prefix = currentNumber.substring(0, currentNumber.length - numStr.length);
    const num = parseInt(numStr, 10) + 1;
    return `${prefix}${String(num).padStart(numStr.length, '0')}`;
};

const formatCurrency = (val: number) => {
    return val.toLocaleString('en-ZA', { style: 'currency', currency: 'ZAR' });
};

interface InvoiceGeneratorProps {
    showToast: (m: string, t: ToastType) => void;
}

const THEMES: { id: InvoiceTheme; name: string; color: string }[] = [
    { id: 'standard', name: 'Classic Pro', color: 'indigo' },
    { id: 'modern', name: 'Ultra Modern', color: 'violet' },
    { id: 'minimal', name: 'Clean Minimal', color: 'slate' },
    { id: 'bold', name: 'High Impact', color: 'rose' }
];

const InvoiceGenerator: React.FC<InvoiceGeneratorProps> = ({ showToast }) => {
    const [details, setDetails] = useState<InvoiceDetails>({
        fromName: 'Your Business Name',
        fromAddress: 'South Africa Office',
        invoiceNumber: DEFAULT_INVOICE_NUMBER,
        date: new Date().toISOString().split('T')[0],
        items: [{ id: 1, description: 'Consulting Services', quantity: 1, unitPrice: 1500 }],
        notes: 'Payment is due within 30 days.',
        theme: 'standard',
    } as InvoiceDetails);

    const [loading, setLoading] = useState(false);
    const [isExportingPdf, setIsExportingPdf] = useState(false);
    const [generatedHtml, setGeneratedHtml] = useState('');
    const { clients } = useClients();

    // Persistence
    useEffect(() => {
        const last = localStorage.getItem(STORAGE_KEYS.LAST_NUMBER);
        if (last) setDetails(prev => ({ ...prev, invoiceNumber: getNextInvoiceNumber(last) }));
    }, []);

    const updateDetail = (field: keyof InvoiceDetails, value: any) => {
        setDetails(prev => ({ ...prev, [field]: value }));
    };

    const handleItemChange = (id: number, field: keyof InvoiceItem, value: any) => {
        setDetails(prev => ({
            ...prev,
            items: prev.items.map(item => item.id === id ? { ...item, [field]: value } : item)
        }));
    };

    const addItem = () => {
        setDetails(prev => ({
            ...prev,
            items: [...prev.items, { id: Date.now(), description: '', quantity: 1, unitPrice: 0 }]
        }));
    };

    const grandTotal = useMemo(() => {
        return details.items.reduce((sum, item) => sum + (item.quantity * item.unitPrice), 0);
    }, [details.items]);

    const handleGenerate = async () => {
        setLoading(true);
        try {
            const html = await generateInvoiceHtml(details);
            setGeneratedHtml(html);
            showToast("Invoice architecture generated successfully.", "success");
        } catch (err: any) {
            showToast(err.message || "Engine failure during generation.", "error");
        } finally {
            setLoading(false);
        }
    };

    const handleExport = async () => {
        if (!generatedHtml) return;
        setIsExportingPdf(true);
        try {
            const el = document.getElementById('invoice-preview-container');
            const { jsPDF } = window.jspdf;
            const pdf = new jsPDF('p', 'mm', 'a4');
            const canvas = await window.html2canvas(el, { scale: 2, useCORS: true });
            const img = canvas.toDataURL('image/png');
            pdf.addImage(img, 'PNG', 10, 10, 190, (190 * canvas.height) / canvas.width);
            pdf.save(`Invoice-${details.invoiceNumber}.pdf`);
            localStorage.setItem(STORAGE_KEYS.LAST_NUMBER, details.invoiceNumber);
            showToast("Document exported and sequence updated.", "success");
        } catch (err) {
            showToast("PDF Export failed.", "error");
        } finally {
            setIsExportingPdf(false);
        }
    };

    return (
        <div className="max-w-[1600px] mx-auto animate-fade-in">
            <div className="flex flex-col lg:flex-row gap-10 items-start">
                {/* STUDIO CONTROLS */}
                <div className="w-full lg:w-[450px] space-y-8">
                    <div>
                        <h1 className="text-3xl font-black text-slate-900 tracking-tight mb-2">Invoice Studio</h1>
                        <p className="text-sm font-medium text-slate-500 italic">"Design professional billing in seconds."</p>
                    </div>

                    <Card className="rounded-[2rem] border-0 shadow-xl overflow-hidden p-0">
                        <div className="bg-indigo-600 p-8 text-white">
                            <h3 className="text-[10px] font-black uppercase tracking-[0.3em] text-indigo-200 mb-4">Branding & Style</h3>
                            <div className="grid grid-cols-2 gap-3">
                                {THEMES.map(t => (
                                    <button 
                                        key={t.id} 
                                        onClick={() => updateDetail('theme', t.id)}
                                        className={`px-4 py-3 rounded-xl text-xs font-black transition-all border ${details.theme === t.id ? 'bg-white text-slate-900 border-white shadow-lg' : 'bg-white/10 border-white/20 text-white hover:bg-white/20'}`}
                                    >
                                        {t.name}
                                    </button>
                                ))}
                            </div>
                        </div>

                        <div className="p-8 space-y-8 bg-white">
                            <section className="space-y-4">
                                <h3 className="text-xs font-black uppercase tracking-widest text-slate-400 border-b border-slate-50 pb-2">Entity Details</h3>
                                <div className="space-y-4">
                                    <Input label="Business Name" id="fromName" value={details.fromName} onChange={e => updateDetail('fromName', e.target.value)} />
                                    <Input label="Invoice Sequence" id="invNo" value={details.invoiceNumber} onChange={e => updateDetail('invoiceNumber', e.target.value)} />
                                    <div>
                                        <label className="block text-xs font-black text-slate-500 uppercase tracking-wider mb-2">Recipient</label>
                                        <select 
                                            onChange={e => {
                                                const c = clients.find(cl => cl.id === e.target.value);
                                                if(c) { updateDetail('toName', c.name); updateDetail('toAddress', c.address); }
                                            }}
                                            className="w-full bg-slate-50 border border-slate-100 rounded-xl px-4 py-3 text-sm focus:bg-white transition-all outline-none"
                                        >
                                            <option value="">Select Saved Client</option>
                                            {clients.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                                        </select>
                                    </div>
                                </div>
                            </section>

                            <section className="space-y-4">
                                <h3 className="text-xs font-black uppercase tracking-widest text-slate-400 border-b border-slate-50 pb-2">Line Items</h3>
                                <div className="space-y-3">
                                    {details.items.map((item, idx) => (
                                        <div key={item.id} className="p-4 bg-slate-50 rounded-2xl border border-slate-100 group relative">
                                            <div className="grid grid-cols-12 gap-3">
                                                <input 
                                                    placeholder="Description"
                                                    value={item.description}
                                                    onChange={e => handleItemChange(item.id, 'description', e.target.value)}
                                                    className="col-span-12 bg-transparent font-bold text-slate-800 outline-none placeholder:text-slate-300"
                                                />
                                                <div className="col-span-4 flex items-center gap-2 bg-white px-2 py-1.5 rounded-lg border border-slate-100">
                                                    <span className="text-[9px] font-black text-slate-400 uppercase">Qty</span>
                                                    <input type="number" value={item.quantity} onChange={e => handleItemChange(item.id, 'quantity', Number(e.target.value))} className="w-full text-xs font-bold outline-none" />
                                                </div>
                                                <div className="col-span-4 flex items-center gap-2 bg-white px-2 py-1.5 rounded-lg border border-slate-100">
                                                    <span className="text-[9px] font-black text-slate-400 uppercase">ZAR</span>
                                                    <input type="number" value={item.unitPrice} onChange={e => handleItemChange(item.id, 'unitPrice', Number(e.target.value))} className="w-full text-xs font-bold outline-none" />
                                                </div>
                                                <div className="col-span-4 flex flex-col items-end justify-center">
                                                    <span className="text-[9px] font-black text-slate-400 uppercase">Line Total</span>
                                                    <span className="text-xs font-black text-slate-800">{formatCurrency(item.quantity * item.unitPrice)}</span>
                                                </div>
                                            </div>
                                            <button 
                                                onClick={() => updateDetail('items', details.items.filter(i => i.id !== item.id))}
                                                className="absolute -right-2 -top-2 h-6 w-6 bg-rose-500 text-white rounded-full flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity shadow-lg"
                                            >
                                                <svg className="h-3 w-3" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg>
                                            </button>
                                        </div>
                                    ))}
                                    <button onClick={addItem} className="w-full py-3 border-2 border-dashed border-slate-100 rounded-2xl text-[10px] font-black text-slate-400 uppercase tracking-widest hover:border-indigo-200 hover:text-indigo-500 transition-all">+ Add Line Item</button>
                                </div>
                            </section>

                            <div className="pt-6 border-t border-slate-50 flex justify-between items-center">
                                <div>
                                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Grand Total Estimate</p>
                                    <p className="text-2xl font-black text-slate-900 tracking-tighter">{formatCurrency(grandTotal)}</p>
                                </div>
                            </div>

                            <Button onClick={handleGenerate} isLoading={loading} className="w-full !rounded-2xl !py-5 shadow-2xl shadow-indigo-100 text-base">Generate Document</Button>
                        </div>
                    </Card>
                </div>

                {/* PAPER PREVIEW */}
                <div className="flex-1 w-full lg:sticky lg:top-24">
                     <div className="mb-6 flex justify-between items-center">
                        <h3 className="text-xs font-black uppercase tracking-[0.3em] text-slate-400">Document Canvas</h3>
                        {generatedHtml && (
                            <div className="flex gap-2">
                                <Button variant="secondary" onClick={() => window.print()} className="!py-2 !px-4 text-xs bg-white">Print</Button>
                                <Button onClick={handleExport} isLoading={isExportingPdf} className="!py-2 !px-4 text-xs">Download PDF</Button>
                            </div>
                        )}
                     </div>

                     <div className="bg-slate-200/50 rounded-[2.5rem] p-4 sm:p-12 shadow-inner min-h-[842px] flex justify-center overflow-hidden">
                        {generatedHtml ? (
                            <div 
                                id="invoice-preview-container"
                                className="w-full max-w-[210mm] bg-white shadow-[0_40px_100px_-20px_rgba(0,0,0,0.1)] rounded-lg overflow-hidden animate-scale-in origin-top"
                                dangerouslySetInnerHTML={{ __html: generatedHtml }}
                            />
                        ) : (
                            <div className="flex flex-col items-center justify-center text-slate-400 text-center space-y-4 py-32">
                                <div className="h-24 w-24 rounded-[2rem] bg-white shadow-xl flex items-center justify-center mb-4">
                                    <svg className="h-10 w-10 text-slate-200" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
                                </div>
                                <p className="text-lg font-black text-slate-900 tracking-tight">Studio Idle.</p>
                                <p className="text-sm font-medium max-w-xs">Fill out the details on the left and click "Generate Document" to build your PDF.</p>
                            </div>
                        )}
                     </div>
                </div>
            </div>
        </div>
    );
};

export default InvoiceGenerator;

import { useState, useEffect, useCallback } from 'react';
import type { Client } from '../types';

const STORAGE_KEY = 'sme-pal-clients';

export const useClients = () => {
    const [clients, setClients] = useState<Client[]>([]);
    const [isLoading, setIsLoading] = useState(true);

    useEffect(() => {
        try {
            const storedClients = localStorage.getItem(STORAGE_KEY);
            if (storedClients) {
                setClients(JSON.parse(storedClients));
            }
        } catch (error) {
            console.error("Failed to load clients from localStorage", error);
        } finally {
            setIsLoading(false);
        }
    }, []);

    const saveClients = useCallback((updatedClients: Client[]) => {
        try {
            // Sort clients alphabetically by name before saving
            const sortedClients = updatedClients.sort((a, b) => a.name.localeCompare(b.name));
            localStorage.setItem(STORAGE_KEY, JSON.stringify(sortedClients));
            setClients(sortedClients);
        } catch (error) {
            console.error("Failed to save clients to localStorage", error);
        }
    }, []);

    const addClient = useCallback((client: Omit<Client, 'id'>) => {
        const newClient = { ...client, id: crypto.randomUUID() };
        const updatedClients = [...clients, newClient];
        saveClients(updatedClients);
    }, [clients, saveClients]);

    const updateClient = useCallback((updatedClient: Client) => {
        const updatedClients = clients.map(c => c.id === updatedClient.id ? updatedClient : c);
        saveClients(updatedClients);
    }, [clients, saveClients]);

    const deleteClient = useCallback((clientId: string) => {
        const updatedClients = clients.filter(c => c.id !== clientId);
        saveClients(updatedClients);
    }, [clients, saveClients]);

    const deleteClients = useCallback((clientIds: string[]) => {
        const updatedClients = clients.filter(c => !clientIds.includes(c.id));
        saveClients(updatedClients);
    }, [clients, saveClients]);

    return { clients, addClient, updateClient, deleteClient, deleteClients, isLoading };
};

import React, { useState, useMemo } from 'react';
import { useClients } from '../hooks/useClients';
import Card from './common/Card';
import Button from './common/Button';
import Spinner from './common/Spinner';
import ClientFormModal from './ClientFormModal';
import type { Client } from '../types';
import type { ToastType } from './common/Toast';

interface ClientManagerProps {
    showToast: (m: string, t: ToastType) => void;
}

const BusinessAvatar: React.FC<{ name: string }> = ({ name }) => {
    const initials = name.split(' ').map(n => n[0]).join('').substring(0, 2).toUpperCase();
    const colors = ['bg-indigo-500', 'bg-violet-500', 'bg-emerald-500', 'bg-rose-500', 'bg-amber-500', 'bg-sky-500'];
    const color = colors[name.length % colors.length];

    return (
        <div className={`h-12 w-12 rounded-[1.2rem] ${color} flex items-center justify-center text-white text-sm font-black shadow-lg shadow-indigo-100`}>
            {initials}
        </div>
    );
};

const ClientManager: React.FC<ClientManagerProps> = ({ showToast }) => {
    const { clients, addClient, updateClient, deleteClient, deleteClients, isLoading } = useClients();
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [clientToEdit, setClientToEdit] = useState<Client | null>(null);
    const [search, setSearch] = useState('');
    const [selectedIds, setSelectedIds] = useState<string[]>([]);

    // Enhanced Search Logic
    const filteredClients = useMemo(() => {
        const term = search.toLowerCase();
        return clients.filter(c => 
            c.name.toLowerCase().includes(term) || 
            c.email?.toLowerCase().includes(term) ||
            c.contactPerson?.toLowerCase().includes(term) ||
            c.address.toLowerCase().includes(term) ||
            c.phone?.toLowerCase().includes(term)
        );
    }, [clients, search]);

    const handleOpenModal = (client: Client | null = null) => {
        setClientToEdit(client);
        setIsModalOpen(true);
    };

    const handleSaveClient = (clientData: Client | Omit<Client, 'id'>) => {
        try {
            if ('id' in clientData) {
                updateClient(clientData as Client);
                showToast("Client profile updated successfully.", "success");
            } else {
                addClient(clientData);
                showToast("New client added to your directory.", "success");
            }
        } catch (e) {
            showToast("Failed to save changes.", "error");
        }
    };

    const handleDelete = (id: string) => {
        if (window.confirm("Archiving this client will remove them from the active directory. Proceed?")) {
            deleteClient(id);
            setSelectedIds(prev => prev.filter(sid => sid !== id));
            showToast("Client successfully archived.", "info");
        }
    };

    const handleBulkDelete = () => {
        if (window.confirm(`Are you sure you want to delete ${selectedIds.length} selected clients?`)) {
            deleteClients(selectedIds);
            setSelectedIds([]);
            showToast(`${selectedIds.length} clients archived successfully.`, "success");
        }
    };

    const toggleSelectAll = () => {
        if (selectedIds.length === filteredClients.length) {
            setSelectedIds([]);
        } else {
            setSelectedIds(filteredClients.map(c => c.id));
        }
    };

    const toggleSelect = (id: string) => {
        setSelectedIds(prev => 
            prev.includes(id) ? prev.filter(sid => sid !== id) : [...prev, id]
        );
    };

    const exportToCSV = (data: Client[]) => {
        const headers = ["Name", "Address", "Contact Person", "Email", "Phone"];
        const rows = data.map(c => [
            `"${c.name.replace(/"/g, '""')}"`,
            `"${c.address.replace(/"/g, '""')}"`,
            `"${(c.contactPerson || '').replace(/"/g, '""')}"`,
            `"${(c.email || '').replace(/"/g, '""')}"`,
            `"${(c.phone || '').replace(/"/g, '""')}"`
        ].join(','));

        const csvContent = [headers.join(','), ...rows].join('\n');
        const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement("a");
        link.setAttribute("href", url);
        link.setAttribute("download", `smepal_clients_${new Date().toISOString().split('T')[0]}.csv`);
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        showToast("Directory exported to CSV.", "success");
    };

    const handleBulkExport = () => {
        const dataToExport = selectedIds.length > 0 
            ? clients.filter(c => selectedIds.includes(c.id))
            : filteredClients;
        exportToCSV(dataToExport);
    };

    return (
        <div className="max-w-6xl mx-auto space-y-8 animate-fade-in">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-6">
                <div>
                    <h1 className="text-4xl font-black text-slate-900 tracking-tight mb-2">Business Directory</h1>
                    <p className="text-slate-500 font-medium italic">Manage your {clients.length} active partnerships.</p>
                </div>
                <div className="flex flex-col sm:flex-row gap-3 w-full md:w-auto">
                    <div className="relative flex-1 md:w-80">
                         <input 
                            type="text" 
                            placeholder="Search names, emails, addresses..."
                            value={search}
                            onChange={e => setSearch(e.target.value)}
                            className="w-full bg-white border border-slate-100 rounded-2xl px-5 py-3 pl-12 text-sm font-medium shadow-sm focus:ring-8 focus:ring-indigo-50 focus:border-indigo-400 transition-all outline-none"
                        />
                        <svg className="absolute left-4 top-3.5 h-5 w-5 text-slate-300" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
                    </div>
                    <div className="flex gap-2">
                        <Button variant="secondary" onClick={() => exportToCSV(clients)} className="!px-4">Export All</Button>
                        <Button onClick={() => handleOpenModal()} className="shadow-xl shadow-indigo-100">+ New Client</Button>
                    </div>
                </div>
            </div>

            {/* Bulk Actions Bar */}
            {selectedIds.length > 0 && (
                <div className="bg-indigo-600 rounded-2xl p-4 flex items-center justify-between animate-soft-reveal shadow-lg">
                    <div className="flex items-center gap-4 text-white">
                        <div className="h-8 w-8 bg-white/20 rounded-lg flex items-center justify-center font-black text-xs">
                            {selectedIds.length}
                        </div>
                        <p className="text-sm font-bold uppercase tracking-widest">Entities Selected</p>
                    </div>
                    <div className="flex gap-2">
                        <Button variant="ghost" onClick={handleBulkExport} className="!bg-white/10 !text-white !border-white/20 hover:!bg-white/20 !py-2">Bulk Export</Button>
                        <Button variant="danger" onClick={handleBulkDelete} className="!bg-rose-500 hover:!bg-rose-600 !py-2">Bulk Delete</Button>
                        <Button variant="ghost" onClick={() => setSelectedIds([])} className="!text-white hover:!bg-white/5 !py-2">Cancel</Button>
                    </div>
                </div>
            )}

            <Card className="rounded-[2.5rem] border-0 shadow-2xl p-0 overflow-hidden">
                {isLoading ? (
                    <div className="p-20 text-center flex flex-col items-center"><Spinner /><p className="mt-4 text-slate-400 font-bold uppercase tracking-widest text-xs">Syncing Directory...</p></div>
                ) : filteredClients.length === 0 ? (
                    <div className="p-32 text-center">
                         <div className="h-20 w-20 bg-slate-50 rounded-[2rem] flex items-center justify-center mx-auto mb-6">
                            <svg className="h-10 w-10 text-slate-200" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M17 20h5v-2a3 3 0 00-5.356-1.857M17 20H7m10 0v-2c0-.653-.124-1.282-.356-1.857M7 20H2v-2a3 3 0 015.356-1.857M7 20v-2c0-.653.124-1.282.356-1.857m0 0a5.002 5.002 0 019.288 0M15 7a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
                         </div>
                         <h3 className="text-xl font-black text-slate-900 tracking-tight">No entities found.</h3>
                         <p className="text-slate-400 text-sm font-medium mt-2 max-w-xs mx-auto">Start building your database or adjust your search to find specific partners.</p>
                         <Button variant="secondary" onClick={() => handleOpenModal()} className="mt-8">Onboard First Client</Button>
                    </div>
                ) : (
                    <div className="overflow-x-auto">
                        <table className="w-full text-left border-collapse">
                            <thead>
                                <tr className="bg-slate-50/50 border-b border-slate-50 text-[10px] font-black uppercase tracking-[0.2em] text-slate-400">
                                    <th className="px-6 py-6 w-10">
                                        <input 
                                            type="checkbox" 
                                            className="h-4 w-4 rounded border-slate-300 text-indigo-600 focus:ring-indigo-600 cursor-pointer"
                                            checked={selectedIds.length === filteredClients.length && filteredClients.length > 0}
                                            onChange={toggleSelectAll}
                                        />
                                    </th>
                                    <th className="px-6 py-6">Partner Identity</th>
                                    <th className="px-6 py-6">Contact Info</th>
                                    <th className="px-6 py-6">Physical Presence</th>
                                    <th className="px-10 py-6 text-right">Actions</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-slate-50">
                                {filteredClients.map((client) => (
                                    <tr key={client.id} className={`group hover:bg-slate-50/30 transition-colors ${selectedIds.includes(client.id) ? 'bg-indigo-50/40' : ''}`}>
                                        <td className="px-6 py-6">
                                             <input 
                                                type="checkbox" 
                                                className="h-4 w-4 rounded border-slate-300 text-indigo-600 focus:ring-indigo-600 cursor-pointer"
                                                checked={selectedIds.includes(client.id)}
                                                onChange={() => toggleSelect(client.id)}
