import React, { useState, useEffect } from 'react';
import Card from './common/Card';
import Button from './common/Button';
import ToggleSwitch from './common/ToggleSwitch';
import Input from './common/Input';

const Settings: React.FC = () => {
    const [settings, setSettings] = useState({
        aiDeepReasoning: true,
        creativeConfidence: 0.85,
        defaultTaxYear: '2024/2025',
        currencySymbol: 'R',
        autoBackup: true,
        compactMode: false,
        highContrastForms: true,
    });

    useEffect(() => {
        const stored = localStorage.getItem('smepal_app_settings');
        if (stored) setSettings(JSON.parse(stored));
    }, []);

    const handleToggle = (key: keyof typeof settings) => {
        const updated = { ...settings, [key]: !settings[key] };
        setSettings(updated);
        localStorage.setItem('smepal_app_settings', JSON.stringify(updated));
    };

    const handleInputChange = (key: keyof typeof settings, value: string | number) => {
        const updated = { ...settings, [key]: value };
        setSettings(updated);
        localStorage.setItem('smepal_app_settings', JSON.stringify(updated));
    };

    const exportData = () => {
        const allData = {
            clients: JSON.parse(localStorage.getItem('sme-pal-clients') || '[]'),
            expenses: JSON.parse(localStorage.getItem('sme-pal-expenses') || '[]'),
            profile: JSON.parse(localStorage.getItem('smepal_business_profile') || '{}'),
            settings
        };
        const blob = new Blob([JSON.stringify(allData, null, 2)], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `smepal_telemetry_${new Date().toISOString().split('T')[0]}.json`;
        a.click();
    };

    const importData = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;
        const reader = new FileReader();
        reader.onload = (ev) => {
            try {
                const data = JSON.parse(ev.target?.result as string);
                if (data.clients) localStorage.setItem('sme-pal-clients', JSON.stringify(data.clients));
                if (data.expenses) localStorage.setItem('sme-pal-expenses', JSON.stringify(data.expenses));
                if (data.profile) localStorage.setItem('smepal_business_profile', JSON.stringify(data.profile));
                if (data.settings) {
                    setSettings(data.settings);
                    localStorage.setItem('smepal_app_settings', JSON.stringify(data.settings));
                }
                alert("Workspace telemetry successfully restored.");
                window.location.reload();
            } catch (err) {
                alert("Failed to parse telemetry file. Ensure it is a valid SMEPal export.");
            }
        };
        reader.readAsText(file);
    };

    const clearTelemetry = () => {
        if (window.confirm("CRITICAL: This will permanently destroy all local business data. This action is compliant with POPIA right-to-be-forgotten protocols. Proceed?")) {
            localStorage.clear();
            window.location.reload();
        }
    };

    return (
        <div className="max-w-5xl mx-auto space-y-10 pb-24 animate-fade-in">
            <div className="text-left space-y-2">
                <h1 className="text-4xl font-black text-slate-800 tracking-tight">System Configuration</h1>
                <p className="text-slate-500 font-medium italic">"Tuning the SMEPal engine for your specific operational requirements."</p>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-10">
                {/* Left: Navigation Categories */}
                <div className="lg:col-span-1 space-y-6">
                    <Card title="Protocol Categories" className="!p-6 border-0 shadow-sm">
                        <nav className="space-y-1">
                            {['Neural Engine', 'Regional Logic', 'Interface Specs', 'Data Sovereignty'].map((cat) => (
                                <button key={cat} className="w-full text-left px-4 py-3 rounded-xl text-sm font-bold text-slate-600 hover:bg-indigo-50 hover:text-indigo-600 transition-all flex items-center justify-between group">
                                    {cat}
                                    <svg className="h-4 w-4 opacity-0 group-hover:opacity-100 transition-opacity" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M9 5l7 7-7 7" /></svg>
                                </button>
                            ))}
                        </nav>
                    </Card>

                    <div className="bg-indigo-600 rounded-[2rem] p-8 text-white shadow-xl relative overflow-hidden">
                        <div className="absolute top-0 right-0 h-24 w-24 bg-white/10 rounded-full -mr-12 -mt-12"></div>
                        <h4 className="text-sm font-black uppercase tracking-widest mb-3">System Health</h4>
                        <div className="flex items-center gap-3">
                            <div className="h-2 w-2 rounded-full bg-emerald-400 animate-pulse"></div>
                            <span className="text-xs font-bold text-indigo-100">Neural Link Stable</span>
                        </div>
                        <p className="mt-4 text-[10px] text-indigo-200 font-medium leading-relaxed italic">"Optimal latency detected for ZAF regional nodes."</p>
                    </div>
                </div>

                {/* Right: Actual Settings */}
                <div className="lg:col-span-2 space-y-8">
                    <Card title="Neural Engine Protocols" className="!p-10 !rounded-[2.5rem] shadow-2xl border-0">
                        <div className="space-y-8">
                            <ToggleSwitch 
                                label="AI Deep Reasoning (Thinking Mode)"
                                description="Increases the processing budget for complex legislative tasks like Tax and Legal drafting."
                                enabled={settings.aiDeepReasoning}
                                setEnabled={() => handleToggle('aiDeepReasoning')}
                            />

                            <div className="space-y-3">
                                <div className="flex justify-between items-center">
                                    <label className="text-sm font-bold text-slate-700">Creativity Confidence</label>
                                    <span className="text-xs font-black text-indigo-600">{(settings.creativeConfidence * 100).toFixed(0)}%</span>
                                </div>
                                <input 
                                    type="range" min="0" max="1" step="0.05"
                                    value={settings.creativeConfidence}
                                    onChange={(e) => handleInputChange('creativeConfidence', parseFloat(e.target.value))}
                                    className="w-full h-1.5 bg-slate-100 rounded-lg appearance-none cursor-pointer accent-indigo-600"
                                />
                                <p className="text-[10px] text-slate-400 font-medium">Controls the balance between factual compliance and creative marketing copy.</p>
                            </div>
                        </div>
                    </Card>

                    <Card title="Regional & Interface Logic" className="!p-10 !rounded-[2.5rem] shadow-2xl border-0">
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-8 mb-10">
                            <Input 
                                label="Default Tax Year" 
