                                    <h4 className="text-sm font-black text-slate-800 uppercase tracking-tight">Telemetry Export</h4>
                                    <p className="text-xs text-slate-400 mt-1">Secure local backup of all business data.</p>
                                </div>
                                <Button variant="secondary" onClick={exportData} className="!px-6 !py-3 !rounded-xl !text-[11px] font-black uppercase">Export Telemetry</Button>
                            </div>

                            <div className="flex flex-col md:flex-row items-center justify-between gap-6 p-6 bg-slate-50 rounded-2xl border border-slate-100 shadow-inner">
                                <div className="text-left">
